import React, { useState } from 'react';
import { NavLink } from 'react-router-dom';
import classNames from 'classnames';
import './Header.scss';

export const Header = () => {
  const [menu, setMenu] = useState('false');

  const menuItems = [
    'Plan you vaccine', 'Covid-19', 'Politics',
    'U.S.News', 'Opinion', 'World', 'Busness', 'Tech',
  ];

  return (
    <header className="Header">
      <div className={classNames('container', {
        container_menu: menu,
      })}
      >
        <h1 className="Header-Logo">NEWS</h1>
        <div className="Header-Menu Menu">
          <ul className={classNames('Menu-List', {
            menu_visible: menu,
          })}
          >
            {menuItems.map(item => (
              <li className="Menu-Item" key={item}>
                <NavLink
                  to={item}
                  className="Menu-Link"
                >
                  {item.toUpperCase()}
                </NavLink>
              </li>
            ))}
          </ul>
          <button
            type="button"
            className={classNames('button-menu', {
              menu_open: !menu,
              menu_cross: menu,
            })}
            onClick={() => setMenu(!menu)}
          />
        </div>
      </div>
      <div className="container-nav">
        <form className="Header-Form">
          <button type="button" className="button-search" />
          <input />
          <button type="button" className="button-clear">D</button>
        </form>
        <nav className="Header-Nav Nav">
          <a href="#home" className="Nav-Item">Home</a>
          <a href="#articles" className="Nav-Item">Articles</a>
        </nav>
      </div>
    </header>
  );
};
